let keys = ['a','s','d','f','g','h','j','k'];

function setup() {
  createCanvas(200, 200);
  osc = new p5.Oscillator('sine');
  osc.start();
  osc.amp(0);
}

function keyPressed() {
  let i = keys.indexOf(key.toLowerCase());
  if (i >= 0) {
    osc.freq(base * ratios[i]);
    osc.amp(0.3, 0.05);
  }
}

function keyReleased() {
  osc.amp(0, 0.1);
