  for (let y = 0; y < height; y++) {
    let amt = map(y, 0, height, 0, 1);
    stroke(lerpColor(c1, c2, amt));
    line(0, y, width, y);
  }

  noStroke();
  for (let i = 0; i < 18; i++) {
    let x = (frameCount * 0.15 + i * 90) % (width + 100) - 50;
    let y = 80 + sin(frameCount * 0.01 + i) * 28 + i * 24;
    fill(255, 255, 255, 24);
    ellipse(x, y, 90, 36);
  }
}

