  vox.disconnect();
  reverb.process(vox, 3, 2);
  reverb.amp(1.2);

  reverbSlider = createSlider(0, 100, 30);
  reverbSlider.position(100, 240);

  panSlider = createSlider(0, 100, 80);
  panSlider.position(100, 280);
}

function draw() {
  background(255, 245, 255);
  createImage(double six.jpg)
  // pastel rectangles
  fill(210, 240, 255);
  rect(100, 100, 100, 60);
  fill(50);
  textSize(14);
