  text("drums", 150, 130);

  fill(230, 250, 220);
  rect(220, 100, 100, 60);
  fill(50);
  text("vocals", 270, 130);

  fill(255, 245, 215);
  rect(340, 100, 100, 60);
  fill(50);
  text("instruments", 390, 130);

  // slider labels
  textAlign(LEFT, CENTER);
  textSize(12);
  fill(50);
  text("drum volume", 100, 195);
  text("vocal reverb", 100, 235);
  text("instrument pan openness", 100, 275);

  // drum volume logic
  let v = drumVol.value() / 100;
  drum.setVolume(v);

  // vocal reverb mix
  let wet = reverbSlider.value() / 100;
  wet = wet * 0.6; 
  reverb.drywet(wet);

  // instrument auto-pan
  if (audioStarted) {
    let openness = panSlider.value() / 100;
    let panValue = sin(panPhase) * openness;
    inst.pan(panValue);
    panPhase += panSpeed;
  }
}

function mousePressed() {
  if (!audioStarted) {
    userStartAudio();
    drum.loop();
    vox.loop();
    inst.loop();
    audioStarted = true;
  }
}

